const inp = $input.item.json;
const body = inp.body || inp;
const text = (body.problem || body.error || '').toString().trim();
if (!text) {
  return [{ json: { ok: false, skip: true, reason: 'Missing problem/error in request body' } }];
}
const runId = `ESHV2-${Date.now()}`;
return [{ json: { ok: true, skip: false, runId, problemText: text } }];

const base = $('normalize_input').first().json;
const sr = $input.item.json;
const results = Array.isArray(sr.results) ? sr.results.slice(0, 5) : [];
const lines = results.map((r, i) => `${i + 1}. ${r.title || 'No title'}\n   ${r.url || ''}`);
const report = [
  '# Error Solution Hunter Report',
  '',
  `Run ID: ${base.runId}`,
  `Problem: ${base.problemText}`,
  '',
  'Top References:',
  lines.length ? lines.join('\n') : 'No references returned from SearXNG',
  '',
  'Status: Real execution completed'
].join('\n');
const filename = `${base.runId}.md`;
const filepath = `/app/logs/solution_reports/${filename}`;
const b64 = Buffer.from(report, 'utf8').toString('base64');
return [{
  json: { runId: base.runId, filepath, refs: results.length },
  binary: {
    reportData: {
      data: b64,
      mimeType: 'text/markdown',
      fileName: filename
    }
  }
}];

const inp = $input.item.json || {};
const fail = $('normalize_input').first().json || {};
if (fail.skip === true) {
  return [{ json: { status: 'rejected', message: fail.reason } }];
}
const built = $('build_report').first().json || {};
const runId = inp.runId || built.runId || 'unknown';
const reportPath = inp.filepath || built.filepath || '';
const refs = (inp.refs ?? built.refs ?? 0);
const writeErr = inp.error ? (typeof inp.error === 'object' ? (inp.error.message || JSON.stringify(inp.error)) : String(inp.error)) : '';
const status = writeErr ? 'partial_success' : 'success';
const message = writeErr ? `Search and report build succeeded, file write failed: ${writeErr}` : 'Workflow executed successfully';
return [{ json: { status, message, runId, reportPath, refs } }];
